# --------------------------------------------------------------------------
# Monitoring Module Variables (Story 7.1)
# Robusta + kube-prometheus-stack for alerting and monitoring.
#
# SENSITIVE VARIABLES: teams_webhook_url, smtp_url, smtp_url_ops,
# grafana_admin_password contain credentials. Mark as sensitive in
# root variables.tf and never commit values to Git.
# --------------------------------------------------------------------------

variable "environment" {
  description = "Environment name (dev, prd)"
  type        = string
  validation {
    condition     = contains(["dev", "prd"], var.environment)
    error_message = "Environment must be 'dev' or 'prd'."
  }
}

variable "robusta_namespace" {
  description = "Kubernetes namespace for Robusta installation"
  type        = string
  default     = "monitoring"
}

variable "robusta_chart_version" {
  description = "Robusta Helm chart version (robusta-charts.storage.googleapis.com)"
  type        = string
  default     = "0.33.0"
  validation {
    condition     = can(regex("^[0-9]+\\.[0-9]+\\.[0-9]+$", var.robusta_chart_version))
    error_message = "Robusta chart version must be valid semver (e.g., '0.33.0')."
  }
}

variable "robusta_helm_timeout" {
  description = "Timeout in seconds for the Robusta Helm release"
  type        = number
  default     = 900
  validation {
    condition     = var.robusta_helm_timeout >= 300 && var.robusta_helm_timeout <= 1800
    error_message = "Helm timeout must be between 300 and 1800 seconds."
  }
}

variable "cluster_name" {
  description = "Name of the AKS cluster (used in alert context)"
  type        = string
}

# --------------------------------------------------------------------------
# Teams Sink Configuration (Task 1)
# --------------------------------------------------------------------------

variable "teams_webhook_url" {
  description = "Power Automate webhook URL for Teams OPS channel. Created via Teams → channel → Workflows → webhook template."
  type        = string
  sensitive   = true
  validation {
    condition     = var.teams_webhook_url == "" || can(regex("^https://", var.teams_webhook_url))
    error_message = "Teams webhook URL must start with https:// or be empty to disable Teams sink."
  }
}

# --------------------------------------------------------------------------
# Email Sink Configuration (Task 2)
# --------------------------------------------------------------------------

variable "smtp_url" {
  description = "Apprise-format SMTP URL for critical/on-call email. Format: mailtos://user:password@smtp.example.com&from=alerts@example.com&to=oncall@example.com"
  type        = string
  sensitive   = true
  default     = ""
}

variable "smtp_url_ops" {
  description = "Apprise-format SMTP URL for ops team email. Format: mailtos://user:password@smtp.example.com&from=alerts@example.com&to=ops@example.com"
  type        = string
  sensitive   = true
  default     = ""
}

# --------------------------------------------------------------------------
# Grafana Configuration
# --------------------------------------------------------------------------

variable "grafana_admin_password" {
  description = "Grafana admin password"
  type        = string
  sensitive   = true
  default     = ""
}

# --------------------------------------------------------------------------
# Common
# --------------------------------------------------------------------------

variable "tags" {
  description = "Tags to apply to resources (if applicable)"
  type        = map(string)
  default     = {}
}

